        ctx.beginPath();
        ctx.moveTo(-s * 0.1, 0);
        ctx.lineTo(s * 0.1, 0);
        ctx.strokeStyle = '#333';
        ctx.lineWidth = 1.5;
        ctx.stroke();
      }
      ctx.restore();

      // --- MOUTH ---
      ctx.save();
      ctx.translate(s * 0.6, s * 0.04);
      ctx.beginPath();
      ctx.arc(0, 0, s * 0.07, Math.PI * 0.1, Math.PI * 0.9);
      ctx.strokeStyle = 'rgba(0,0,0,0.4)';
      ctx.lineWidth = 1.5;
      ctx.stroke();
      ctx.restore();

      ctx.restore();
    }

    // --- Seaweed ---
    const seaweeds = Array.from({ length: 8 }, () => ({
      x: 60 + Math.random() * (window.innerWidth - 120),
      segments: 6 + Math.floor(Math.random() * 5),
      phase: Math.random() * Math.PI * 2,
      speed: 0.015 + Math.random() * 0.02,
      height: 55 + Math.random() * 60,
      color: `hsl(${130 + Math.random() * 40}, 60%, ${30 + Math.random() * 20}%)`,
    }));

    function drawSeaweed(sw, t) {
      sw.phase += sw.speed;
      ctx.save();
      ctx.translate(sw.x, canvas.height);
      const segH = sw.height / sw.segments;
      ctx.beginPath();
      ctx.moveTo(0, 0);
      for (let i = 0; i <= sw.segments; i++) {
        const sway = Math.sin(sw.phase + i * 0.6) * (i * 4);
        ctx.lineTo(sway, -i * segH);
      }
      ctx.strokeStyle = sw.color;
      ctx.lineWidth = 4 - sw.segments * 0.1;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.shadowBlur = 4;
      ctx.shadowColor = sw.color;
      ctx.stroke();
      ctx.restore();
    }

    let t = 0;
    function animate() {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      t++;

      drawWater();
      drawCaustics(t);

      // Seaweed (bottom)
      seaweeds.forEach(sw => drawSeaweed(sw, t));

      // Bubbles
      bubbles.forEach(b => drawBubble(b));

      // Fish
      fish.forEach(f => drawFish(f, t));

      // Surface ripple overlay
      drawSurfaceWaves();

      animId = requestAnimationFrame(animate);
    }

    animate();

    return () => {
      cancelAnimationFrame(animId);
      window.removeEventListener('resize', resize);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      style={{
        position: 'fixed',
        top: 0,
        left: 0,
        width: '100vw',
        height: '100vh',
        zIndex: -1,
        pointerEvents: 'none',
        display: 'block',
      }}
    />
  );
}
